def validate_schema(data, schema):
    """
    Validate a dictionary against a JSON schema.
    Returns a tuple of (is_valid: bool, errors: list of error messages)
    """
    errors = []

    # Check if data is a dictionary
    if not isinstance(data, dict):
        return False, ["Data must be a dictionary"]

    # Check required fields
    required = schema.get('required', [])
    for field in required:
        if field not in data:
            errors.append(f"Missing required field: {field}")

    # Check properties
    properties = schema.get('properties', {})
    for key, value in data.items():
        if key in properties:
            prop_schema = properties[key]
            expected_type = prop_schema.get('type')

            # Type checking
            if expected_type == 'string' and not isinstance(value, str):
                errors.append(f"Field '{key}' must be a string")
            elif expected_type == 'number' and not isinstance(value, (int, float)):
                errors.append(f"Field '{key}' must be a number")
            elif expected_type == 'boolean' and not isinstance(value, bool):
                errors.append(f"Field '{key}' must be a boolean")
            elif expected_type == 'object' and not isinstance(value, dict):
                errors.append(f"Field '{key}' must be an object")
            elif expected_type == 'array' and not isinstance(value, list):
                errors.append(f"Field '{key}' must be an array")

            # If it's an object, recursively validate nested schema
            if expected_type == 'object' and isinstance(value, dict):
                nested_schema = prop_schema.get('properties', {})
                nested_required = prop_schema.get('required', [])
                nested_result, nested_errors = validate_schema(value, {
                    'properties': nested_schema,
                    'required': nested_required
                })
                if not nested_result:
                    errors.extend([f"In nested object '{key}': {err}" for err in nested_errors])

            # If it's an array, check items if schema is provided
            if expected_type == 'array' and isinstance(value, list):
                items_schema = prop_schema.get('items', {})
                if items_schema:
                    for i, item in enumerate(value):
                        if items_schema.get('type') == 'object' and isinstance(item, dict):
                            item_result, item_errors = validate_schema(item, items_schema)
                            if not item_result:
                                errors.extend([f"In array '{key}' at index {i}: {err}" for err in item_errors])
                        else:
                            # Simple type check for array items
                            expected_item_type = items_schema.get('type')
                            if expected_item_type == 'string' and not isinstance(item, str):
                                errors.append(f"Item at index {i} in '{key}' must be a string")
                            elif expected_item_type == 'number' and not isinstance(item, (int, float)):
                                errors.append(f"Item at index {i} in '{key}' must be a number")

    return len(errors) == 0, errors

